// Lookup by slug
export function getSubjectBySlug(slug: string): Subject | undefined {
 return allSubjects.find(s => s.slug === slug);
}

// Group by level
export function getSubjectsByLevel(level: Subject["level"]): Subject[] {
 return allSubjects.filter(s => s.level === level);
}
